module top_module (
    input clk,
    input reset,
    input up,
    output [2:0] count );reg [2:0] cnt_reg;

    always @(posedge clk) begin
        if (reset)
            cnt_reg <= 3'b000;
        else if (up)
            cnt_reg <= cnt_reg + 1;
        else
            cnt_reg <= cnt_reg - 1;
    end

    assign count = cnt_reg;

endmodule
